import{_ as l,B as n,c as s,o as t,j as r,a3 as d,a as i,b as c,e as p,t as h}from"./chunks/framework.IjbGqw7S.js";const w=JSON.parse('{"title":"v5.30.40 (32987)","description":"","frontmatter":{"editLink":false,"prev":false,"next":false},"headers":[],"params":{"title":"v5.30.40 (32987)","versionName":"v5.30.40","versionCode":32987,"preRelease":false},"relativePath":"changelog/32987.md","filePath":"en/changelog/[versionCode].md"}'),u={name:"changelog/32987.md"},m={id:"params-title",tabindex:"-1"};function g(a,e,b,f,k,v){const o=n("Badge");return t(),s("div",{"data-pagefind-body":!0},[r("h1",m,[i(h(a.$params.title)+" ",1),a.$params.preRelease?(t(),c(o,{key:0,type:"warning",text:"PR"})):p("",!0),e[0]||(e[0]=i()),e[1]||(e[1]=r("a",{class:"header-anchor",href:"#params-title","aria-label":'Permalink to "{{ $params.title }} <Badge v-if="$params.preRelease" type="warning" text="PR" />"'},"​",-1))]),e[2]||(e[2]=d('<h2 id="important-and-bracking-changes" tabindex="-1">Important and bracking changes <a class="header-anchor" href="#important-and-bracking-changes" aria-label="Permalink to &quot;Important and bracking changes&quot;">​</a></h2><ul><li><strong>Backup Notice:</strong> This version will delete all added repos! Please backup before updating due to major internal repo structure changes. Migration isn&#39;t feasible for this update.</li><li>Users must select a root provider manually now.</li><li>JavaScript KernelSU API and FileSystem API must be allowed by the user for access.</li></ul><h2 id="what-s-new" tabindex="-1">What&#39;s New <a class="header-anchor" href="#what-s-new" aria-label="Permalink to &quot;What&#39;s New&quot;">​</a></h2><ul><li><p><strong>New Screens &amp; Features:</strong></p><ul><li>Repositories have been split into their own screen.</li><li>Re-worked Module, Repo cards, and layout.</li><li>Repositories moved to the main screen.</li><li>New red border added to blacklisted modules.</li><li>Added the ability to open WebUI by clicking on the module card.</li><li>WebUI now supports dynamic theme colors and more customizable options.</li><li>WebUI&#39;s API access is now restricted by default for increased security.</li><li>Added the <code>track.json</code> file option to modules for easier tracking.</li><li>Platform management improvements and added support for unsupported compressions.</li></ul></li><li><p><strong>Enhanced Features:</strong></p><ul><li>Improved navigation and UI with a new <code>CompositionLocalProvider</code> for <code>navController</code>.</li><li>Action and Module install process can now be canceled (developer-only feature).</li><li>New <code>MAGISKTMP</code> and <code>ASHSTANDALONE=1</code> added to actions.</li><li>Re-enabled updaters, though functionality is uncertain.</li><li>Added KernelSU Next support and improved related features.</li><li>Added option to sort modules by action or WebUI.</li><li>Added date preview for events.</li><li>A new option to export modules as text has been included.</li></ul></li><li><p><strong>Other Improvements:</strong></p><ul><li>Updated translations and added new languages.</li><li>Storage usage display improved, replacing the ratio placeholder.</li><li>Fixed issues with root status card, corner radius, and module analytics.</li><li>Reworked Module cover design and added category labels to cards.</li><li>Improved the action and install cancel functionality.</li><li>Action and install cancellation now works more universally.</li><li>Improved internal components and clearer error reporting (e.g., crash screen, deprecated icons).</li><li>Clear command added to both action and module installers.</li></ul></li><li><p><strong>Security Enhancements:</strong></p><ul><li>User now needs to allow JavaScript KernelSU API access for increased security.</li><li>WebUI access now requires manual permission for API functionality.</li><li>Blacklist blocks listed modules from being installed locally, with an option to disable via Settings &gt; Security &gt; Blacklist Alerts.</li></ul></li></ul><h2 id="translation-updates" tabindex="-1">Translation Updates: <a class="header-anchor" href="#translation-updates" aria-label="Permalink to &quot;Translation Updates:&quot;">​</a></h2><ul><li>Polish by <a href="https://github.com/Daviteusz" target="_blank" rel="noreferrer">@Daviteusz</a> &amp; Eryk Michalak</li><li>German by <a href="https://github.com/DerGoogler" target="_blank" rel="noreferrer">@DerGoogler</a>, <a href="https://github.com/MrAnderson187" target="_blank" rel="noreferrer">@MrAnderson187</a>, <a href="https://github.com/ImBss" target="_blank" rel="noreferrer">@ImBss</a></li><li>Arabic by <a href="https://github.com/ZG089" target="_blank" rel="noreferrer">@ZG089</a></li><li>Japanese by <a href="https://github.com/reindex-ot" target="_blank" rel="noreferrer">@reindex-ot</a></li><li>Portuguese by <a href="https://github.com/ggeo-git" target="_blank" rel="noreferrer">@ggeo-git (404)</a></li><li>Vietnamese by Lnothem</li><li>Chinese (Traditional Han script) by <a href="https://github.com/GenshoOpen" target="_blank" rel="noreferrer">@GenshoOpen</a></li><li>Chinese (Simplified Han script) by <a href="https://github.com/Uiugkhbkhbkg" target="_blank" rel="noreferrer">@Uiugkhbkhbkg</a> &amp; <a href="https://github.com/AronnaxM" target="_blank" rel="noreferrer">@AronnaxM</a></li><li>Indonesian by <a href="https://github.com/Rem01Gaming" target="_blank" rel="noreferrer">@Rem01Gaming</a></li><li>Spanish by <a href="https://github.com/GuestAnotdev" target="_blank" rel="noreferrer">@GuestAnotdev</a> &amp; gallegonovato</li><li>Italian by <a href="https://github.com/diegoberaldin" target="_blank" rel="noreferrer">@diegoberaldin</a></li></ul><h2 id="other-notes" tabindex="-1">Other Notes: <a class="header-anchor" href="#other-notes" aria-label="Permalink to &quot;Other Notes:&quot;">​</a></h2><ul><li>Weblate support added to the about screen.</li><li>Some components, like the <code>repo.json</code> API, have been extended.</li><li>Some deprecated modules now display an icon.</li><li>WebUI can now load assets either with or without shell support.</li><li>Fixed some issues with non-scrollable settings and fixed the install process when choosing modules from other apps (e.g., Telegram).</li></ul><hr><p>This version includes significant internal improvements, security measures, and a more streamlined user experience.</p>',10))])}const _=l(u,[["render",g]]);export{w as __pageData,_ as default};
